func SplitOrders(orders []Order, vehicles []Vehicle, workHours float64) []SubOrder {
	caps := make([]float64, 0)
	for _, vehicle := range vehicles {
		if vehicle.Capacity > 0 && vehicle.Count > 0 {
			caps = append(caps, vehicle.Capacity)
		}
	}
	for i := 0; i < len(caps); i++ {
		for j := i + 1; j < len(caps); j++ {
			if caps[j] > caps[i] {
				caps[i], caps[j] = caps[j], caps[i]
			}
		}
	}
	if len(caps) == 0 {
		return []SubOrder{}
	}
	result := make([]SubOrder, 0)
	largest := caps[0]
	for _, order := range orders {
		remaining := order.Volume
		for remaining > 1e-9 {
			chosen := largest
			for _, cap := range caps {
				if remaining <= cap+1e-9 {
					chosen = cap
				}
			}
			volume := remaining
			if volume > chosen {
				volume = chosen
			}
			result = append(result, SubOrder{OrderID: order.ID, Volume: volume, VehicleCapacity: chosen})
			remaining -= volume
		}
	}
	return result
}
